#include<bits/stdc++.h>
using namespace std;
int a[100010];
double b[100010];
int n,s,t;
bool check(double x)
{
    for(int i=1;i<=n;i++)
    {
        b[i]=b[i-1]+a[i]-x;
    }
    deque<int> q;
    for(int i=1;i<=n;i++)
    {
        if(i>=s)
        {
            while(!q.empty()&&b[q.back()]>b[i-s])
            {
                q.pop_back();
            }
            q.push_back(i-s);
        }
        while(!q.empty()&&q.front()<i-t)
        {
            q.pop_front();
        }
        if(!q.empty()&&b[i]>=b[q.front()])
        {
            return true;
        }
    }
    return false;
}
int main()
{
    scanf("%d%d%d",&n,&s,&t);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    double l=-10000,r=10000,best;
    while(r-l>1e-5)
    {
        double mid=(l+r)/2;
        if(check(mid))
        {
            l=mid;
            best=mid;
        }
        else
        {
            r=mid;
        }
    }
    printf("%.3lf",best);
    return 0;
}
